-- ---------------------------------------------------------- Tabel structuur voor tabel dagelijksetrek-- --------------------------------------------------------DROP TABLE IF EXISTS dagelijksetrek;CREATE TABLE IF NOT EXISTS dagelijksetrek (id smallint(14) NOT NULL auto_increment,persoon_id smallint(11) NOT NULL default '0',datum date NOT NULL default '0000-00-00',hoeveel smallint(6) default NULL,uitglijer tinyint(3) NOT NULL default '0',redenondermax  smallint(6) default NULL,redenbovenmax  smallint(6) default NULL,cue smallint(6) default NULL,contekst smallint(6) default NULL,gevoel smallint(6) default NULL,gedachte smallint(6) default NULL,PRIMARY KEY (id),KEY persoon_id (persoon_id),KEY datum (datum)) TYPE=MyISAM AUTO_INCREMENT=100 ;-- Gegevens worden uitgevoerd voor tabel dagelijksetrekINSERT INTO dagelijksetrek VALUES ('', 0, '2006-09-26', 2, 0, 110, 111,112,113,114,115);